/// <summary>
/// The ETGSalesAgreementWFTypeEventHandler workflow event handler.
/// </summary>
public class  ETGSalesAgreementWFTypeEventHandler implements WorkflowCanceledEventHandler,  
	WorkflowCompletedEventHandler,
	WorkflowStartedEventHandler
{
}

Method.Source:
public void started(WorkflowEventArgs _workflowEventArgs)
{
    // TODO:  Write code to execute once the workflow is started.
}

public void completed(WorkflowEventArgs _workflowEventArgs)
{
    RecId documentRecId = _workflowEventArgs.parmWorkflowContext().parmRecId();
    SalesAgreementHeader::updateWorkflowStatus(documentRecId, VersioningDocumentState::Approved);

    if (ETGACFParameters::find().EnableDMSIntegration 
        && BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereSalesAgreementIntegrationEventClass)))
    {

        SalesAgreementHeader     salesAgreementHeader;
        AgreementHeaderHistory   agreementHeaderHistory;

        select firstonly salesAgreementHeader
        where salesAgreementHeader.RecId == documentRecId;

        select firstonly agreementHeaderHistory
                    order by RecId desc
                      where agreementHeaderHistory.AgreementHeader == salesAgreementHeader.RecId;

        str confirmationnumber  = strFmt("%1-%2", salesAgreementHeader.SalesNumberSequence, agreementHeaderHistory.ConfirmationNumber);
        str formattedDateTime = DateTimeUtil::toStr(agreementHeaderHistory.CreatedDateTime);

        ETGDMSRevereSalesAgreementIntegrationContract contract = new ETGDMSRevereSalesAgreementIntegrationContract();

        contract.parmDealNumber(salesAgreementHeader.ETGDMSDealNumber);
        contract.parmDataAreaId(curExt());
        contract.parmOperationType("Agreement Workflow Approval");
        contract.parmActivityName("Sales Agreement Workflow Approval");
        contract.parmDocumentNumber(confirmationnumber);
        contract.parmDocumentDate(formattedDateTime);
        contract.parmActivityOwner(salesAgreementHeader.CreatedBy);
        contract.parmActivityRemarks(strFmt("The Sale agreement %1 is approved",salesAgreementHeader.SalesNumberSequence));

        ETGDMSRevereSalesAgreementIntegrationEventClass eventClass = ETGDMSRevereSalesAgreementIntegrationEventClass::newFromContract(contract);
        eventClass.send();
    }




}

public void changeRequested(WorkflowElementEventArgs _workflowElementEventArgs)
{
    RecId documentRecId = _workflowElementEventArgs.parmWorkflowContext().parmRecId();
    SalesAgreementHeader::updateWorkflowStatus(documentRecId, VersioningDocumentState::Draft);
}

private void clearWorkFlowState(WorkflowEventArgs _workflowEventArgs)
{
    WorkflowContext workflowContext = _workflowEventArgs.parmWorkflowContext();
    RecId salesAgreementRecId = workflowContext.parmRecId();
    SalesAgreementHeader salesAgreementHeader;

    ttsbegin;      
    select firstonly forupdate salesAgreementHeader
        where salesAgreementHeader.RecId == salesAgreementRecId;

    salesAgreementHeader.ETGWorkflowStatus = VersioningDocumentState::Draft;
    salesAgreementHeader.doUpdate();
    ttscommit;
}
